def transform(input_grid: list[list[int]]) -> list[list[int]]:
    grid = [row[:] for row in input_grid]
    R = len(grid)
    if R == 0:
        return grid
    C = len(grid[0])

    visited = [[False]*C for _ in range(R)]
    stack = []

    # Initialize stack with all boundary cells that are 0
    for r in range(R):
        for c in [0, C-1]:
            if grid[r][c] == 0:
                stack.append((r, c))
                visited[r][c] = True
    for c in range(C):
        for r in [0, R-1]:
            if grid[r][c] == 0 and not visited[r][c]:
                stack.append((r, c))
                visited[r][c] = True

    # Flood fill from boundaries to mark all 0s connected to the edge
    while stack:
        r, c = stack.pop()
        for dr, dc in [(-1,0), (1,0), (0,-1), (0,1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < R and 0 <= nc < C:
                if grid[nr][nc] == 0 and not visited[nr][nc]:
                    visited[nr][nc] = True
                    stack.append((nr, nc))

    # Any remaining 0s are enclosed holes; fill them with 4
    for r in range(R):
        for c in range(C):
            if grid[r][c] == 0 and not visited[r][c]:
                grid[r][c] = 4

    return grid
