import numpy as np

def transform(input_grid: list[list[int]]) -> list[list[int]]:
    grid = np.array(input_grid)

    # Identify the grid color (the non-zero color that forms the grid lines)
    first_row_colors = set(grid[0])
    grid_color = next(c for c in first_row_colors if c != 0)

    out = grid.copy()
    unique_colors = sorted(set(np.unique(grid)) - {0, grid_color})

    for color in unique_colors:
        positions = np.argwhere(grid == color)
        if len(positions) < 2:
            continue

        rows = {}
        cols = {}
        for r, c in positions:
            rows.setdefault(r, []).append(c)
            cols.setdefault(c, []).append(r)

        to_fill = set()

        # Horizontal expansion
        for r, cs in rows.items():
            if len(cs) >= 2:
                min_c, max_c = min(cs), max(cs)
                for c in range(min_c, max_c + 1):
                    if out[r, c] in (0, grid_color):
                        to_fill.add((r, c))

        # Vertical expansion
        for c, rs in cols.items():
            if len(rs) >= 2:
                min_r, max_r = min(rs), max(rs)
                for r in range(min_r, max_r + 1):
                    if out[r, c] in (0, grid_color):
                        to_fill.add((r, c))

        for r, c in to_fill:
            out[r, c] = color

    return out.tolist()
