    H = len(input_grid)
    W = len(input_grid[0])

    # Identify grid color (assumed to be the color forming the grid lines)
    grid_color = input_grid[2][0]

    # Calculate number of cells
    R_cells = (H + 1) // 3
    C_cells = (W + 1) // 3

    # Extract cell values from the input grid
    cells = [[0] * C_cells for _ in range(R_cells)]
    for i in range(R_cells):
        for j in range(C_cells):
            val = input_grid[3*i + 1][3*j + 1]
            if val != 0 and val != grid_color:
                cells[i][j] = val

    # Group initial positions by color
    color_rows = defaultdict(lambda: defaultdict(set))
    color_cols = defaultdict(lambda: defaultdict(set))

    for i in range(R_cells):
        for j in range(C_cells):
            c = cells[i][j]
            if c != 0:
                color_rows[c][i].add(j)
                color_cols[c][j].add(i)

