def transform(input_grid: list[list[int]]) -> list[list[int]]:
    rows = len(input_grid)
    if rows == 0:
        return []
    cols = len(input_grid[0])

    visited = [[False] * cols for _ in range(rows)]
    components = []

    for r in range(rows):
        for c in range(cols):
            if input_grid[r][c] == 5 and not visited[r][c]:
                comp = []
                stack = [(r, c)]
                visited[r][c] = True
                while stack:
                    cr, cc = stack.pop()
                    comp.append((cr, cc))
                    for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                        nr, nc = cr + dr, cc + dc
                        if 0 <= nr < rows and 0 <= nc < cols and input_grid[nr][nc] == 5 and not visited[nr][nc]:
                            visited[nr][nc] = True
                            stack.append((nr, nc))
                components.append(comp)

    components.sort(key=lambda comp: (-len(comp), min(r for r, c in comp), min(c for r, c in comp)))

    output = [[0] * cols for _ in range(rows)]
    for i, comp in enumerate(components):
        label = i + 1
        for r, c in comp:
            output[r][c] = label

    return output
