import numpy as np

def transform(input_grid: list[list[int]]) -> list[list[int]]:
    grid = np.array(input_grid)
    h, w = grid.shape
    result = grid.copy()

    # Block boundaries
    block_rows = [0, 4, 8]
    block_cols = [0, 4, 8]

    for br in block_rows:
        for bc in block_cols:
            block = grid[br:br+3, bc:bc+3]
            non_zeros = []
            for r in range(3):
                for c in range(3):
                    val = block[r, c]
                    if val != 0 and val != 5:
                        non_zeros.append((val, r, c))

            if not non_zeros:
                continue

            # Filter out 8 as it seems to be a distractor
            candidates = [(v, r, c) for v, r, c in non_zeros if v != 8]
            if not candidates:
                candidates = non_zeros # Fallback if all are 8

            # Heuristic: pick the candidate closest to the center (1,1)
            # Break ties by picking the smallest value
            def score(item):
                v, r, c = item
                dist = abs(r - 1) + abs(c - 1)
                return (dist, v)

            best = min(candidates, key=score)
            fill_val = best[0]

            # Fill the block
            result[br:br+3, bc:bc+3] = fill_val

    return result.tolist()
