import numpy as np
from collections import Counter

def transform(input_grid: list[list[int]]) -> list[list[int]]:
    grid = np.array(input_grid)
    h, w = grid.shape

    sep_rows = set(np.where(np.all(grid == 0, axis=1))[0])
    sep_cols = set(np.where(np.all(grid == 0, axis=0))[0])

    def get_ranges(sep_set, max_idx):
        ranges, start = [], 0
        for i in range(max_idx):
            if i in sep_set:
                if start < i: ranges.append((start, i))
                start = i + 1
        if start < max_idx: ranges.append((start, max_idx))
        return ranges

    row_ranges = get_ranges(sep_rows, h)
    col_ranges = get_ranges(sep_cols, w)

    blocks = []
    for rs, re in row_ranges:
        for cs, ce in col_ranges:
            block = grid[rs:re, cs:ce]
            nz = block[block != 0]
            colors = tuple(sorted(np.unique(nz))) if nz.size else ()
            blocks.append((block, colors))

    if not blocks: return []

    counts = Counter(c for _, c in blocks)
    most_common = counts.most_common(1)[0][0]

    for block, colors in blocks:
        if colors != most_common:
            return block.tolist()
    return blocks[0][0].tolist()
