def transform(input_grid: list[list[int]]) -> list[list[int]]:
    import numpy as np
    grid = np.array(input_grid)
    h, w = grid.shape

    zero_rows = [i for i in range(h) if np.all(grid[i] == 0)]
    zero_cols = [j for j in range(w) if np.all(grid[:, j] == 0)]

    if not zero_rows or not zero_cols:
        return input_grid

    r_top = zero_rows[0]
    r_bot = zero_rows[-1] + 1
    c_left = zero_cols[0]
    c_right = zero_cols[-1] + 1

    quads = [
        ('TL', grid[:r_top, :c_left]),
        ('TR', grid[:r_top, c_right:]),
        ('BL', grid[r_bot:, :c_left]),
        ('BR', grid[r_bot:, c_right:])
    ]

    quad_colors = {}
    for name, q in quads:
        mask = q != 0
        if np.any(mask):
            quad_colors[name] = int(q[mask][0])

    color_count = {}
    for name, color in quad_colors.items():
        color_count[color] = color_count.get(color, 0) + 1

    target_color = next((c for c, cnt in color_count.items() if cnt == 1), None)

    if target_color is not None:
        for name, q in quads:
            if quad_colors.get(name) == target_color:
                return q.tolist()

    return input_grid
